              <div className="mb-6">
                <h3 className="text-lg font-semibold text-white flex items-center gap-2">
                  <Book className="h-5 w-5 text-[#00FF66] drop-shadow-[0_0_8px_#00FF66]" />
                  Quick Start Guide
