      () => import('../transactions'),
      () => import('../verify-merchant'),
    ];

    // Test all imports simultaneously
    const importPromises = componentImports.map(async (importFn, index) => {
      try {
        const module = await importFn();
        return {
          index,
          success: true,
          hasDefault: !!module.default,
        };
