} from "lucide-react";
import { useIsMobile } from "@/hooks/use-mobile";

interface MerchantDetails {
  id: number;
  name: string;
  businessName: string;
  contactEmail: string;
  contactPhone: string;
  businessAddress: string;
  currentProviderRate: string;
  bankName: string;
  bankAccountNumber: string;
  bankBranch: string;
  accountHolderName: string;
  qrCodeUrl: string;
  paymentUrl: string;
