@import url('https://fonts.googleapis.com/css2?family=Inter:wght@100;200;300;400;500;600;700&display=swap');

@tailwind base;
@tailwind components;
@tailwind utilities;

/* 3D Flip Animation Utilities */
.perspective-1000 {
  perspective: 1000px;
}

.preserve-3d {
  transform-style: preserve-3d;
}

.backface-hidden {
  backface-visibility: hidden;
}

.rotate-y-180 {
  transform: rotateY(180deg);
}

:root {
  --background: hsl(0, 0%, 100%);
  --foreground: hsl(20, 14.3%, 4.1%);
  --muted: hsl(60, 4.8%, 95.9%);
  --muted-foreground: hsl(25, 5.3%, 44.7%);
  --popover: hsl(0, 0%, 100%);
  --popover-foreground: hsl(20, 14.3%, 4.1%);
  --card: hsl(0, 0%, 100%);
  --card-foreground: hsl(20, 14.3%, 4.1%);
  --border: hsl(20, 5.9%, 90%);
  --input: hsl(20, 5.9%, 90%);
  --primary: hsl(155, 40%, 25%);
  --primary-foreground: hsl(0, 0%, 100%);
  --secondary: hsl(60, 4.8%, 95.9%);
  --secondary-foreground: hsl(24, 9.8%, 10%);
  --accent: hsl(60, 4.8%, 95.9%);
  --accent-foreground: hsl(24, 9.8%, 10%);
  --destructive: hsl(0, 84.2%, 60.2%);
  --destructive-foreground: hsl(60, 9.1%, 97.8%);
  --ring: hsl(20, 14.3%, 4.1%);
  --radius: 0.5rem;

  /* Custom colors matching design */
  --merchant-teal: hsl(155, 40%, 25%);
  --slider-orange: hsl(25, 60%, 75%);
  --bg-light: hsl(210, 20%, 98%);

  /* Tapt brand colors */
  --forest-green: hsl(155, 60%, 20%);
  --forest-green-light: hsl(155, 40%, 25%);
  --bronze: hsl(30, 50%, 60%);
  --bronze-light: hsl(30, 40%, 70%);
}

.dark {
  --background: hsl(240, 10%, 3.9%);
  --foreground: hsl(0, 0%, 98%);
  --muted: hsl(240, 3.7%, 15.9%);
  --muted-foreground: hsl(240, 5%, 64.9%);
  --popover: hsl(240, 10%, 3.9%);
  --popover-foreground: hsl(0, 0%, 98%);
  --card: hsl(240, 10%, 3.9%);
  --card-foreground: hsl(0, 0%, 98%);
  --border: hsl(240, 3.7%, 15.9%);
  --input: hsl(240, 3.7%, 15.9%);
  --primary: hsl(155, 40%, 25%);
  --primary-foreground: hsl(0, 0%, 100%);
  --secondary: hsl(240, 3.7%, 15.9%);
  --secondary-foreground: hsl(0, 0%, 98%);
  --accent: hsl(240, 3.7%, 15.9%);
  --accent-foreground: hsl(0, 0%, 98%);
  --destructive: hsl(0, 62.8%, 30.6%);
  --destructive-foreground: hsl(0, 0%, 98%);
  --ring: hsl(240, 4.9%, 83.9%);
  --radius: 0.5rem;
}

@keyframes gradientMove {
  0% {
    background-position: 0% 50%;
  }
  50% {
    background-position: 100% 50%;
  }
  100% {
    background-position: 0% 50%;
  }
}

@keyframes gradient {
  0% {
    background-position: 0% 50%;
  }
  50% {
    background-position: 100% 50%;
  }
  100% {
    background-position: 0% 50%;
  }
}

/* Simple payment status animations */
@keyframes fadeIn {
  0% {
    opacity: 0;
    transform: scale(0.8);
  }
  100% {
    opacity: 1;
    transform: scale(1);
  }
}

@keyframes scaleIn {
  0% {
    transform: scale(0);
  }
  100% {
    transform: scale(1);
  }
}

@layer base {
  * {
    @apply border-border;
  }

  body {
    @apply font-sans antialiased bg-background text-foreground;
    font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', 'Roboto', 'Oxygen', 'Ubuntu', 'Cantarell', 'Fira Sans', 'Droid Sans', 'Helvetica Neue', sans-serif;
    font-weight: 400;
    letter-spacing: -0.01em;
    line-height: 1.6;
  }
}

  /* Enhanced Typography */
  h1, h2, h3, h4, h5, h6 {
    font-weight: 600;
    letter-spacing: -0.025em;
    line-height: 1.2;
  }

  h1 {
    font-weight: 700;
    letter-spacing: -0.03em;
  }

  h2 {
    font-weight: 600;
    letter-spacing: -0.025em;
  }

  h3 {
    font-weight: 500;
    letter-spacing: -0.02em;
  }

  /* Clean button and input typography */
  button, input, select, textarea {
    font-family: inherit;
    font-weight: 300;
    letter-spacing: -0.01em;
  }

  /* Ultra-light weight for brand text */
  .brand-text {
    font-weight: 100;
    letter-spacing: 0.05em;
  }

  /* Minimalist spacing for cards and components */
  .minimal-text {
    font-weight: 200;
    letter-spacing: -0.015em;
    line-height: 1.5;
  }

/* Page Transition Animations */
@layer utilities {
  .page-enter {
    transform: translateX(100%);
    opacity: 0;
  }

  .page-enter-active {
    transform: translateX(0);
    opacity: 1;
    transition: all 300ms ease-out;
  }

  .page-exit {
    transform: translateX(0);
    opacity: 1;
  }

  .page-exit-active {
    transform: translateX(-100%);
    opacity: 0;
    transition: all 300ms ease-in;
  }

  .page-transition-container {
    position: relative;
    overflow: hidden;
    width: 100%;
    min-height: 100vh;
    transform-style: preserve-3d;
  }

  .page-wrapper {
    position: relative;
    width: 100%;
    min-height: 100vh;
    transform: none;
    will-change: transform, opacity;
    transform-origin: center;
    backface-visibility: hidden;
  }
}

/* Slide animations with different directions */
@keyframes slideInFromRight {
  from {
    transform: translateX(100%);
    opacity: 0;
  }
  to {
    transform: translateX(0);
    opacity: 1;
  }
}

@keyframes slideOutToLeft {
  from {
    transform: translateX(0);
    opacity: 1;
  }
  to {
    transform: translateX(-100%);
    opacity: 0;
  }
}

@keyframes slideInFromLeft {
  from {
    transform: translateX(-100%);
    opacity: 0;
  }
  to {
    transform: translateX(0);
    opacity: 1;
  }
}

@keyframes slideOutToRight {
  from {
    transform: translateX(0);
    opacity: 1;
  }
  to {
    transform: translateX(100%);
    opacity: 0;
  }
}

.slide-enter-right {
  animation: slideInFromRight 350ms cubic-bezier(0.4, 0, 0.2, 1) forwards;
}

.slide-exit-left {
  animation: slideOutToLeft 350ms cubic-bezier(0.4, 0, 0.2, 1) forwards;
}

.slide-enter-left {
  animation: slideInFromLeft 350ms cubic-bezier(0.4, 0, 0.2, 1) forwards;
}

.slide-exit-right {
  animation: slideOutToRight 350ms cubic-bezier(0.4, 0, 0.2, 1) forwards;
}

/* Mobile Menu Animations */
@keyframes slideDownAndFadeIn {
  from {
    opacity: 0;
    transform: translateY(-20px) scale(0.95);
    max-height: 0;
  }
  to {
    opacity: 1;
    transform: translateY(0) scale(1);
    max-height: 500px;
  }
}

@keyframes slideUpAndFadeOut {
  from {
    opacity: 1;
    transform: translateY(0) scale(1);
    max-height: 500px;
  }
  to {
    opacity: 0;
    transform: translateY(-20px) scale(0.95);
    max-height: 0;
  }
}

.mobile-menu-enter {
  animation: slideDownAndFadeIn 300ms cubic-bezier(0.4, 0, 0.2, 1) forwards;
  transform-origin: top center;
}

.mobile-menu-exit {
  animation: slideUpAndFadeOut 250ms cubic-bezier(0.4, 0, 0.2, 1) forwards;
  transform-origin: top center;
}

.mobile-menu-container {
  overflow: hidden;
  will-change: transform, opacity, max-height;
}

/* Staggered menu item animations */
@keyframes menuItemSlideIn {
  from {
    opacity: 0;
    transform: translateX(-20px);
  }
  to {
    opacity: 1;
    transform: translateX(0);
  }
}

.mobile-menu-enter .flex a {
  animation: menuItemSlideIn 200ms cubic-bezier(0.4, 0, 0.2, 1) forwards;
  opacity: 0;
}

/* Glass effect for dashboard cards */
.dashboard-card-glass {
  backdrop-filter: blur(16px);
  background: rgba(255, 255, 255, 0.1);
  border: 1px solid rgba(255, 255, 255, 0.2);
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.1);
  transition: all 0.3s ease;
}

.dashboard-card-glass:hover {
  background: rgba(255, 255, 255, 0.15);
  border-color: rgba(255, 255, 255, 0.3);
  transform: translateY(-2px);
  box-shadow: 0 12px 40px rgba(0, 0, 0, 0.15);
}

/* Custom animations for slide-to-pay */
.slide-to-pay-container {
  background: linear-gradient(90deg, var(--merchant-teal) 0%, var(--merchant-teal) 100%);
}

.slide-to-pay-handle {
  background-color: var(--slider-orange);
  transition: transform 0.2s ease-out;
}

.slide-to-pay-handle:hover {
  transform: scale(1.05);
}

.slide-to-pay-handle:active {
  transform: scale(0.95);
}

/* Mobile optimizations */
@media (max-width: 640px) {
  /* Ensure touch targets are at least 44px */
  button, 
  [role="button"], 
  input[type="submit"], 
  input[type="button"] {
    min-height: 44px;
    min-width: 44px;
  }

  /* Improve form input spacing on mobile */
  input[type="text"], 
  input[type="email"], 
  input[type="password"], 
  input[type="number"], 
  textarea, 
  select {
    min-height: 44px;
    font-size: 16px; /* Prevents zoom on iOS */
  }

  /* Optimize card spacing for mobile */
  .card {
    margin-bottom: 1rem;
  }

  /* Ensure readable text sizes */
  .text-xs {
    font-size: 0.75rem;
    line-height: 1.4;
  }

  .text-sm {
    font-size: 0.875rem;
    line-height: 1.4;
  }

  /* Terminal page mobile optimizations */
  .backdrop-blur-xl {
    /* Glass morphism - transparent background */
    background: rgba(255, 255, 255, 0.05) !important;
    border: 1px solid rgba(255, 255, 255, 0.15) !important;
  }

  /* Better mobile button visibility */
  .backdrop-blur-sm:not(.glow-green-button) {
    background: rgba(255, 255, 255, 0.08) !important;
    border: 1px solid rgba(255, 255, 255, 0.20) !important;
  }

  /* Ensure form labels are visible */
  label {
    color: rgba(255, 255, 255, 0.95) !important;
    font-weight: 500;
  }

  /* Glass input styling */
  input {
    background: rgba(255, 255, 255, 0.08) !important;
    border: 1px solid rgba(255, 255, 255, 0.20) !important;
    color: black !important;
  }

  input::placeholder {
    color: rgba(0, 0, 0, 0.6) !important;
  }

  input:focus {
    background: rgba(255, 255, 255, 0.12) !important;
    border: 1px solid rgba(255, 255, 255, 0.30) !important;
  }

  /* COMPLETE TABLE TRANSPARENCY OVERRIDE - MOBILE ONLY */
  table,
  tbody,
  thead,
  tr,
  td,
  th,
  .dashboard-card-glass table,
  .dashboard-card-glass tbody,
  .dashboard-card-glass thead,
  .dashboard-card-glass tr,
  .dashboard-card-glass td,
  .dashboard-card-glass th,
  .backdrop-blur-lg,
  .bg-white\/5 {
    background: transparent !important;
    background-color: transparent !important;
  }

  /* Force all transaction container transparency */
  .dashboard-card-glass .backdrop-blur-lg,
  .dashboard-card-glass .bg-white\/5 {
    background: rgba(255, 255, 255, 0.02) !important;
    background-color: rgba(255, 255, 255, 0.02) !important;
  }

  /* CRITICAL: Override shadcn muted backgrounds that cause white backgrounds */
  .bg-muted,
  .bg-muted\/50,
  [data-state=selected],
  tr:hover,
  tr[data-state=selected] {
    background: transparent !important;
    background-color: transparent !important;
  }

  /* Override the wrapper div around table that might have background */
  .relative.w-full.overflow-auto {
    background: transparent !important;
    background-color: transparent !important;
  }
}

/* Tablet optimizations */
@media (min-width: 641px) and (max-width: 1024px) {
  /* Optimize layout for tablet portrait/landscape */
  .grid-cols-2 {
    gap: 1rem;
  }

  .grid-cols-4 {
    grid-template-columns: repeat(2, 1fr);
  }
}

/* Dynamic glow pulse animations */
@keyframes glow-pulse {
  0%, 100% {
    opacity: 0.4;
    transform: scale(1);
    filter: blur(40px);
  }
  50% {
    opacity: 0.8;
    transform: scale(1.1);
    filter: blur(60px);
  }
}

@keyframes float-slow {
  0%, 100% {
    transform: translateY(0px) translateX(0px);
  }
  25% {
    transform: translateY(-20px) translateX(10px);
  }
  50% {
    transform: translateY(-10px) translateX(-15px);
  }
  75% {
    transform: translateY(-30px) translateX(5px);
  }
}

@keyframes float-reverse {
  0%, 100% {
    transform: translateY(0px) translateX(0px);
  }
  25% {
    transform: translateY(15px) translateX(-10px);
  }
  50% {
    transform: translateY(25px) translateX(20px);
  }
  75% {
    transform: translateY(5px) translateX(-5px);
  }
}

/* Dynamic moving gradient animations */
@keyframes gradient-x {
  0%, 100% {
    transform: translateX(-50%) translateY(0%);
  }
  50% {
    transform: translateX(50%) translateY(-10%);
  }
}

@keyframes gradient-y {
  0%, 100% {
    transform: translateX(0%) translateY(-50%);
  }
  50% {
    transform: translateX(-20%) translateY(50%);
  }
}

/* Apply animations */
.animate-gradient-x {
  animation: gradient-x 15s ease-in-out infinite;
}

.animate-gradient-y {
  animation: gradient-y 20s ease-in-out infinite reverse;
}

/* Glowing green button effect */
.glow-green-button {
  position: relative;
  overflow: hidden;
}

.glow-green-button::before {
  content: '';
  position: absolute;
  top: 0;
  left: -100%;
  width: 100%;
  height: 100%;
  background: linear-gradient(90deg, transparent, rgba(255, 255, 255, 0.2), transparent);
  transition: left 0.5s;
}

.glow-green-button:hover::before {
  left: 100%;
}

.glow-green-button:disabled {
  opacity: 0.7;
  cursor: not-allowed;
}

.glow-green-button:disabled:hover {
  box-shadow: none !important;
}

/* Mobile specific green button styling */
@media (max-width: 640px) {
  .glow-green-button {
    background: linear-gradient(90deg, rgba(34, 197, 94, 0.8), rgba(16, 185, 129, 0.8), rgba(74, 222, 128, 0.8)) !important;
    border: 1px solid rgba(74, 222, 128, 0.5) !important;
    box-shadow: 0 0 15px rgba(34, 197, 94, 0.3) !important;
  }

  .glow-green-button:hover {
    background: linear-gradient(90deg, rgba(74, 222, 128, 0.9), rgba(16, 185, 129, 0.9), rgba(34, 197, 94, 0.9)) !important;
    border: 1px solid rgba(74, 222, 128, 0.6) !important;
    box-shadow: 0 0 20px rgba(34, 197, 94, 0.5) !important;
  }
}

/* Liquid Glass Admin Dashboard Animations */
@keyframes liquidFloat {
  0%, 100% {
    transform: translateY(0px) translateX(0px) scale(1);
  }
  33% {
    transform: translateY(-20px) translateX(10px) scale(1.1);
  }
  66% {
    transform: translateY(10px) translateX(-10px) scale(0.9);
  }
}

@keyframes liquidPulse {
  0%, 100% {
    transform: scale(1);
    opacity: 0.2;
  }
  50% {
    transform: scale(1.2);
    opacity: 0.3;
  }
}

@keyframes liquidRotate {
  0% {
    transform: rotate(0deg);
  }
  100% {
    transform: rotate(360deg);
  }
}

/* Animation delay utilities */
.animation-delay-300 {
  animation-delay: 300ms;
}

.animation-delay-500 {
  animation-delay: 500ms;
}

.animation-delay-700 {
  animation-delay: 700ms;
}

.animation-delay-1000 {
  animation-delay: 1000ms;
}

/* Glass morphism backdrop utilities */
.backdrop-blur-3xl {
  backdrop-filter: blur(64px);
}

.backdrop-blur-2xl {
  backdrop-filter: blur(40px);
}

/* Liquid glass hover effects */
.liquid-hover {
  transition: all 0.4s cubic-bezier(0.4, 0, 0.2, 1);
}

.liquid-hover:hover {
  transform: translateY(-8px) scale(1.02);
  box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.25);
}

/* Advanced glass morphism containers */
.glass-container {
  background: rgba(255, 255, 255, 0.02);
  backdrop-filter: blur(40px);
  border: 1px solid rgba(255, 255, 255, 0.1);
  box-shadow: 
    0 8px 32px 0 rgba(31, 38, 135, 0.37),
    inset 0 1px 0 0 rgba(255, 255, 255, 0.05);
}

.glass-container-hover {
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

.glass-container-hover:hover {
  background: rgba(255, 255, 255, 0.05);
  border: 1px solid rgba(255, 255, 255, 0.2);
  transform: translateY(-2px);
}

/* Shimmer loading effect */
@keyframes shimmer {
  0% {
    background-position: -200px 0;
  }
  100% {
    background-position: calc(200px + 100%) 0;
  }
}

.shimmer {
  background: linear-gradient(90deg, transparent, rgba(255, 255, 255, 0.1), transparent);
  background-size: 200px 100%;
  animation: shimmer 2s infinite;
}

/* iPhone 12 and Mobile Specific Optimizations */
@media (max-width: 768px) {
  /* Prevent horizontal scrolling */
  body {
    overflow-x: hidden;
  }

  /* Ensure all content stays within viewport */
  * {
    max-width: 100vw;
    box-sizing: border-box;
  }

  /* Improve text rendering on mobile */
  body {
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
    text-size-adjust: 100%;
  }

  /* Prevent zoom on input focus (iOS Safari) */
  input, select, textarea {
    font-size: 16px !important;
  }
}

/* iPhone 12 specific optimizations */
@media (max-width: 390px) {
  /* Extra tight spacing for small screens */
  .space-y-4 > * + * {
    margin-top: 0.75rem !important;
  }

  .space-y-6 > * + * {
    margin-top: 1rem !important;
  }

  /* Smaller padding for very small screens */
  .p-4 {
    padding: 0.75rem !important;
  }

  .px-4 {
    padding-left: 0.75rem !important;
    padding-right: 0.75rem !important;
  }

  .py-4 {
    padding-top: 0.75rem !important;
    padding-bottom: 0.75rem !important;
  }
}

/* Slow Floating Animations - No Blur */
@keyframes slowFloat1 {
  0%, 100% { 
    transform: translate(0, 0);
  }
  50% { 
    transform: translate(30px, -20px);
  }
}

@keyframes slowFloat2 {
  0%, 100% { 
    transform: translate(0, 0);
  }
  50% { 
    transform: translate(-20px, 30px);
  }
}

/* Floating Shape Animations */
@keyframes floatShape1 {
  0%, 100% { 
    transform: translate(0, 0) rotate(0deg);
  }
  50% { 
    transform: translate(15px, -25px) rotate(10deg);
  }
}

@keyframes floatShape2 {
  0%, 100% { 
    transform: translate(0, 0) rotate(0deg);
  }
  50% { 
    transform: translate(-20px, 20px) rotate(-15deg);
  }
}

@keyframes floatShape3 {
  0%, 100% { 
    transform: translate(0, 0) rotate(0deg);
  }
  50% { 
    transform: translate(-15px, -15px) rotate(12deg);
  }
}

@keyframes floatShape4 {
  0%, 100% { 
    transform: translate(0, 0) rotate(0deg);
  }
  50% { 
    transform: translate(20px, 15px) rotate(-10deg);
  }
}

@keyframes floatShape5 {
  0%, 100% { 
    transform: translate(0, 0) rotate(0deg);
  }
  50% { 
    transform: translate(-10px, -20px) rotate(20deg);
  }
}

@keyframes floatShape6 {
  0%, 100% { 
    transform: translate(0, 0) rotate(0deg);
  }
  50% { 
    transform: translate(25px, 10px) rotate(-8deg);
  }
}

/* Lava Lamp Morphing Animations */
@keyframes lavaLamp1 {
  0%, 100% {
    transform: translate(0, 0) scale(1);
  }
  25% {
    transform: translate(40px, -60px) scale(1.2);
  }
  50% {
    transform: translate(-30px, -40px) scale(0.9);
  }
  75% {
    transform: translate(50px, 20px) scale(1.1);
  }
}

@keyframes lavaLamp2 {
  0%, 100% {
    transform: translate(0, 0) scale(1);
  }
  25% {
    transform: translate(-50px, 30px) scale(0.85);
  }
  50% {
    transform: translate(20px, -50px) scale(1.15);
  }
  75% {
    transform: translate(-40px, -30px) scale(0.95);
  }
}

@keyframes lavaLamp3 {
  0%, 100% {
    transform: translate(0, 0) scale(1);
  }
  20% {
    transform: translate(-35px, 45px) scale(1.1);
  }
  40% {
    transform: translate(45px, -35px) scale(0.9);
  }
  60% {
    transform: translate(-25px, -55px) scale(1.2);
  }
  80% {
    transform: translate(35px, 25px) scale(0.85);
  }
}

@keyframes lavaLamp4 {
  0%, 100% {
    transform: translate(0, 0) scale(1);
  }
  30% {
    transform: translate(55px, 40px) scale(1.15);
  }
  60% {
    transform: translate(-45px, -25px) scale(0.9);
  }
}

@keyframes lavaLamp5 {
  0%, 100% {
    transform: translate(0, 0) scale(1);
  }
  25% {
    transform: translate(-60px, -40px) scale(1.25);
  }
  50% {
    transform: translate(40px, 50px) scale(0.8);
  }
  75% {
    transform: translate(-30px, 30px) scale(1.05);
  }
}

@keyframes lavaLamp6 {
  0%, 100% {
    transform: translate(0, 0) scale(1);
  }
  33% {
    transform: translate(30px, -45px) scale(1.1);
  }
  66% {
    transform: translate(-40px, 35px) scale(0.95);
  }
}

/* Animation Utility Classes */
@layer utilities {
  .animate-slow-float-1 {
    animation: slowFloat1 20s ease-in-out infinite;
  }

  .animate-slow-float-2 {
    animation: slowFloat2 25s ease-in-out infinite;
  }

  .animate-float-shape-1 {
    animation: floatShape1 15s ease-in-out infinite;
  }

  .animate-float-shape-2 {
    animation: floatShape2 18s ease-in-out infinite;
  }

  .animate-float-shape-3 {
    animation: floatShape3 20s ease-in-out infinite;
  }

  .animate-float-shape-4 {
    animation: floatShape4 16s ease-in-out infinite;
  }

  .animate-float-shape-5 {
    animation: floatShape5 14s ease-in-out infinite;
  }

  .animate-float-shape-6 {
    animation: floatShape6 17s ease-in-out infinite;
  }

  .animate-lava-lamp-1 {
    animation: lavaLamp1 18s ease-in-out infinite;
  }

  .animate-lava-lamp-2 {
    animation: lavaLamp2 22s ease-in-out infinite;
  }

  .animate-lava-lamp-3 {
    animation: lavaLamp3 25s ease-in-out infinite;
  }

  .animate-lava-lamp-4 {
    animation: lavaLamp4 20s ease-in-out infinite;
  }

  .animate-lava-lamp-5 {
    animation: lavaLamp5 28s ease-in-out infinite;
  }

  .animate-lava-lamp-6 {
    animation: lavaLamp6 24s ease-in-out infinite;
  }
}

/* Respect user's motion preferences */
@media (prefers-reduced-motion: reduce) {
  .animate-slow-float-1,
  .animate-slow-float-2,
  .animate-float-shape-1,
  .animate-float-shape-2,
  .animate-float-shape-3,
  .animate-float-shape-4,
  .animate-float-shape-5,
  .animate-float-shape-6,
  .animate-lava-lamp-1,
  .animate-lava-lamp-2,
  .animate-lava-lamp-3,
  .animate-lava-lamp-4,
  .animate-lava-lamp-5,
  .animate-lava-lamp-6 {
    animation: none;
  }
}

