          </div>

          {/* Small Line Chart Widget */}
          <div className="relative w-32 h-14 flex-shrink-0 -ml-2">
            <ResponsiveContainer width="100%" height="100%">
              <LineChart data={customerGrowthData} margin={{ top: 5, right: 10, bottom: 5, left: 0 }}>
                <Line 
