      const result = await response.json();
      console.log('Account creation result:', result);

      if (result.success) {
        setSuccessMessage('Account created! Please try logging in now.');
      } else {
        setErrors({ general: result.error || 'Failed to create account' });
      }
    } catch (error) {
      console.error('Create account error:', error);
      setErrors({ general: 'Failed to create account' });
    } finally {
      setLoading(false);
    }
  };

  const validateForm = () => {
    const newErrors: { email?: string; password?: string; general?: string } = {};

    // Email validation
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!email) {
      newErrors.email = 'Email is required';
    } else if (!emailRegex.test(email)) {
      newErrors.email = 'Please enter a valid email';
    }

    // Password validation
    if (!password) {
      newErrors.password = 'Password is required';
    } else if (password.length < 6) {
      newErrors.password = 'Password must be at least 6 characters';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setErrors({});
    setSuccessMessage('');

    if (!validateForm()) return;

    setLoading(true);

    try {
      console.log('Attempting login with:', { email, passwordLength: password.length });

      const response = await fetch(
        `https://${projectId}.supabase.co/functions/v1/make-server-a4cbc891/login`,
        {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${publicAnonKey}`,
          },
          body: JSON.stringify({ email, password }),
        }
      );

      const result = await response.json();
      console.log('Login response:', result);

      if (!result.success) {
        console.error('Login error:', result.error);
        setErrors({ general: result.error || 'Invalid email or password' });
      } else {
        console.log('Login successful for user:', result.user.email);
        setSuccessMessage('Login successful!');
        // Store the access token
        localStorage.setItem('accessToken', result.accessToken);
        setTimeout(() => {
          onLoginSuccess(result.user);
        }, 500);
      }
    } catch (error) {
      console.error('Login exception:', error);
      setErrors({ general: 'An unexpected error occurred' });
    } finally {
      setLoading(false);
    }
  };

  const handleSignup = async (e: React.FormEvent) => {
    e.preventDefault();
    setErrors({});
    setSuccessMessage('');

    if (!validateForm()) return;

    setLoading(true);

    try {
      const response = await fetch(
        `https://${projectId}.supabase.co/functions/v1/make-server-a4cbc891/signup`,
        {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${publicAnonKey}`,
          },
          body: JSON.stringify({ email, password, name }),
        }
      );

      const result = await response.json();

      if (!result.success) {
        console.error('Signup error:', result.error);
        setErrors({ general: result.error || 'Failed to create account' });
      } else {
        setSuccessMessage('Account created! You can now log in.');
        setIsSignup(false);
        setEmail('');
        setPassword('');
        setName('');
      }
    } catch (error) {
      console.error('Signup exception:', error);
      setErrors({ general: 'An unexpected error occurred' });
    } finally {
      setLoading(false);
    }
  };

  const handleSocialLogin = async (provider: 'google' | 'apple' | 'github') => {
    try {
      setErrors({});
      const { error } = await supabase.auth.signInWithOAuth({
        provider: provider,
      });

      if (error) {
        console.error(`${provider} login error:`, error);
        setErrors({ general: `Failed to login with ${provider}` });
      }
    } catch (error) {
      console.error(`${provider} login exception:`, error);
      setErrors({ general: 'An unexpected error occurred' });
    }
  };

  const handleForgotPassword = async () => {
    if (!email) {
      setErrors({ general: 'Please enter your email address first' });
      return;
    }

