              <div className="mb-4 p-3 md:p-4 bg-red-500 text-white rounded-full text-center">
                {errors.general}
              </div>
            )}

            {/* Form */}
            <form onSubmit={isSignup ? handleSignup : handleLogin} className="space-y-6 md:space-y-8">
