                  onChange={(e) => {
                    setEmail(e.target.value);
                    if (errors.email) setErrors({ ...errors, email: undefined });
                  }}
                  className={`w-full bg-transparent border-2 ${
                    errors.email ? 'border-red-500' : 'border-[#00E5CC]'
