              >
                Forgot password?
              </button>
              <button 
                onClick={() => {
                  setIsSignup(!isSignup);
                  setErrors({});
                  setSuccessMessage('');
                }}
                className="w-full text-left text-[#0055FF] hover:underline"
              >
                {isSignup ? 'Already have an account? Login' : 'Create account'}
              </button>
              <button className="w-full text-left text-[#0055FF] hover:underline">
                Help & Support
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

