import { useState, useEffect } from 'react';
import { Home, Package, BarChart3, SlidersHorizontal, Download, Calendar, TrendingUp, TrendingDown, DollarSign, CreditCard, ArrowUpDown, ChevronDown } from 'lucide-react';
