                      </g>
                    </g>
                  </svg>
                  </button>
                </div>
              ) : (
                <div className="relative mb-4 sm:mb-5">
                  <button 
                    onClick={handleDigitalPayment}
                    className="w-full bg-white hover:bg-gray-100 rounded-[4px] py-3 sm:py-4 flex items-center justify-center transition-colors shadow-md"
                  >
