                    maxLength={5}
                  />
                  <Input
                    type="text"
                    placeholder="CVV"
                    value={cvv}
                    onChange={(e) => setCvv(e.target.value)}
                    className="bg-gray-100 border-0 rounded-[16px] py-6 text-[#0055FF] placeholder:text-gray-400"
                    maxLength={3}
                  />
                </div>
